 DIALPAD SUPER ADMIN DASHBOARD Database Schema Document PostgreSQL | Supabase | JavaScript Only 1. Entity Relationship Overview The database mirrors Dialpad&apos;s company hierarchy and adds application-specific tables for read tracking, notifications, and user management. Table Purpose users Application login accounts (super admin + invited users) offices Offices under the company â€” synced from Dialpad departments Departments inside each office agents Individual agents assigned to departments agent_status Live agent availability status (Available, Busy, DND, Offline) customers External contacts (customers) who communicate with the company messages All SMS messages: inbound, outbound, internal agent-to-agent message_threads Groups messages into conversations between parties message_read_log Tracks which app users read which messages â€” WhatsApp-style seen calls All call records: inbound, outbound, missed, voicemail notifications In-app notifications independent of Dialpad seen status webhook_events Raw webhook event log for debugging and audit audit_log Admin action history (user added, deleted, password changed) 2. Full SQL Schema 2.1 users CREATE TABLE users ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email VARCHAR(255) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, name VARCHAR(255), role VARCHAR(50) NOT NULL DEFAULT &apos;admin&apos; CHECK (role IN (&apos;superadmin&apos;, &apos;admin&apos;)), is_active BOOLEAN NOT NULL DEFAULT TRUE, must_change_password BOOLEAN NOT NULL DEFAULT TRUE, last_login_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); Field Notes: role: only &quot;superadmin&quot; or &quot;admin&quot; allowed must_change_password: set TRUE on creation, set FALSE after first password change password_hash: bcrypt hash, never store plain text 2.2 offices CREATE TABLE offices ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), dialpad_id VARCHAR(100) NOT NULL UNIQUE, name VARCHAR(255) NOT NULL, phone_number VARCHAR(50), timezone VARCHAR(100), is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); 2.3 departments CREATE TABLE departments ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), dialpad_id VARCHAR(100) NOT NULL UNIQUE, office_id UUID NOT NULL REFERENCES offices(id) ON DELETE CASCADE, name VARCHAR(255) NOT NULL, phone_number VARCHAR(50), is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_departments_office_id ON departments(office_id); 2.4 agents CREATE TABLE agents ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), dialpad_id VARCHAR(100) NOT NULL UNIQUE, department_id UUID REFERENCES departments(id) ON DELETE SET NULL, office_id UUID REFERENCES offices(id) ON DELETE SET NULL, name VARCHAR(255) NOT NULL, email VARCHAR(255), phone_number VARCHAR(50), is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_agents_department_id ON agents(department_id); CREATE INDEX idx_agents_office_id ON agents(office_id); 2.5 agent_status CREATE TABLE agent_status ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), agent_id UUID NOT NULL REFERENCES agents(id) ON DELETE CASCADE, status VARCHAR(50) NOT NULL CHECK (status IN (&apos;available&apos;, &apos;busy&apos;, &apos;dnd&apos;, &apos;offline&apos;)), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); -- One row per agent, upserted on every status webhook event CREATE UNIQUE INDEX idx_agent_status_agent_id ON agent_status(agent_id); 2.6 customers CREATE TABLE customers ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), dialpad_id VARCHAR(100) UNIQUE, phone_number VARCHAR(50) NOT NULL, name VARCHAR(255), email VARCHAR(255), company_name VARCHAR(255), job_title VARCHAR(255), is_active BOOLEAN NOT NULL DEFAULT TRUE, first_contact_at TIMESTAMPTZ, last_contact_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_customers_phone ON customers(phone_number); 2.7 message_threads CREATE TABLE message_threads ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), thread_type VARCHAR(50) NOT NULL CHECK (thread_type IN (&apos;customer&apos;, &apos;internal&apos;)), -- For customer threads: customer_id UUID REFERENCES customers(id) ON DELETE SET NULL, department_id UUID REFERENCES departments(id) ON DELETE SET NULL, -- For internal threads (agent to agent): agent_a_id UUID REFERENCES agents(id) ON DELETE SET NULL, agent_b_id UUID REFERENCES agents(id) ON DELETE SET NULL, last_message_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_threads_customer_id ON message_threads(customer_id); CREATE INDEX idx_threads_department_id ON message_threads(department_id); CREATE INDEX idx_threads_last_message ON message_threads(last_message_at DESC); 2.8 messages CREATE TABLE messages ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), dialpad_id VARCHAR(100) UNIQUE, thread_id UUID NOT NULL REFERENCES message_threads(id) ON DELETE CASCADE, sender_type VARCHAR(50) NOT NULL CHECK (sender_type IN (&apos;agent&apos;, &apos;customer&apos;, &apos;system&apos;)), sender_agent_id UUID REFERENCES agents(id) ON DELETE SET NULL, sender_customer_id UUID REFERENCES customers(id) ON DELETE SET NULL, content TEXT NOT NULL, direction VARCHAR(20) NOT NULL CHECK (direction IN (&apos;inbound&apos;, &apos;outbound&apos;, &apos;internal&apos;)), delivery_status VARCHAR(50) DEFAULT &apos;delivered&apos; CHECK (delivery_status IN (&apos;sending&apos;, &apos;delivered&apos;, &apos;failed&apos;, &apos;undelivered&apos;)), is_internal BOOLEAN NOT NULL DEFAULT FALSE, sent_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_messages_thread_id ON messages(thread_id); CREATE INDEX idx_messages_sent_at ON messages(sent_at DESC); CREATE INDEX idx_messages_sender_agent ON messages(sender_agent_id); CREATE INDEX idx_messages_sender_customer ON messages(sender_customer_id); 2.9 message_read_log (WhatsApp-style Seen Tracking) CREATE TABLE message_read_log ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), message_id UUID NOT NULL REFERENCES messages(id) ON DELETE CASCADE, reader_user_id UUID REFERENCES users(id) ON DELETE SET NULL, read_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); -- Prevent duplicate read entries for same user + message CREATE UNIQUE INDEX idx_read_log_unique ON message_read_log(message_id, reader_user_id); CREATE INDEX idx_read_log_message_id ON message_read_log(message_id); CREATE INDEX idx_read_log_user_id ON message_read_log(reader_user_id); How this works: When a user opens a conversation in YOUR app, a POST to /api/messages/read/:messageId is called This inserts a row: which user read which message, at what time To show &quot;Seen by&quot; info: JOIN message_read_log with users on reader_user_id This is 100% independent of Dialpad â€” Dialpad&apos;s seen status is never used 2.10 calls CREATE TABLE calls ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), dialpad_call_id VARCHAR(100) NOT NULL UNIQUE, agent_id UUID REFERENCES agents(id) ON DELETE SET NULL, customer_id UUID REFERENCES customers(id) ON DELETE SET NULL, department_id UUID REFERENCES departments(id) ON DELETE SET NULL, direction VARCHAR(20) NOT NULL CHECK (direction IN (&apos;inbound&apos;, &apos;outbound&apos;)), status VARCHAR(30) NOT NULL CHECK (status IN (&apos;ringing&apos;, &apos;connected&apos;, &apos;ended&apos;, &apos;missed&apos;, &apos;voicemail&apos;)), started_at TIMESTAMPTZ, connected_at TIMESTAMPTZ, ended_at TIMESTAMPTZ, duration_seconds INTEGER, recording_url TEXT, transcript_url TEXT, ai_summary TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_calls_agent_id ON calls(agent_id); CREATE INDEX idx_calls_customer_id ON calls(customer_id); CREATE INDEX idx_calls_started_at ON calls(started_at DESC); CREATE INDEX idx_calls_status ON calls(status); 2.11 notifications CREATE TABLE notifications ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), event_type VARCHAR(50) NOT NULL CHECK (event_type IN (&apos;sms_inbound&apos;, &apos;missed_call&apos;, &apos;voicemail&apos;, &apos;internal_message&apos;)), source_type VARCHAR(30) NOT NULL CHECK (source_type IN (&apos;customer&apos;, &apos;agent&apos;)), source_id UUID, thread_id UUID REFERENCES message_threads(id) ON DELETE SET NULL, call_id UUID REFERENCES calls(id) ON DELETE SET NULL, preview_text TEXT, is_read BOOLEAN NOT NULL DEFAULT FALSE, read_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_notifications_is_read ON notifications(is_read); CREATE INDEX idx_notifications_created_at ON notifications(created_at DESC); 2.12 webhook_events (Audit / Debug Log) CREATE TABLE webhook_events ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), event_type VARCHAR(100) NOT NULL, dialpad_event_id VARCHAR(100), raw_payload JSONB NOT NULL, processed BOOLEAN NOT NULL DEFAULT FALSE, error_message TEXT, received_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), processed_at TIMESTAMPTZ ); CREATE INDEX idx_webhook_events_type ON webhook_events(event_type); CREATE INDEX idx_webhook_events_processed ON webhook_events(processed); CREATE INDEX idx_webhook_events_received ON webhook_events(received_at DESC); Every webhook received is saved here first â€” even before processing. If processing fails, error_message is populated. This allows replaying failed events. 2.13 audit_log CREATE TABLE audit_log ( id UUID PRIMARY KEY DEFAULT gen_random_uuid(), performed_by UUID REFERENCES users(id) ON DELETE SET NULL, action VARCHAR(100) NOT NULL, target_type VARCHAR(50), target_id UUID, details JSONB, performed_at TIMESTAMPTZ NOT NULL DEFAULT NOW() ); CREATE INDEX idx_audit_log_performed_by ON audit_log(performed_by); CREATE INDEX idx_audit_log_action ON audit_log(action); CREATE INDEX idx_audit_log_performed_at ON audit_log(performed_at DESC); 3. Key Queries Reference Get all messages in a thread with read info: SELECT m.id, m.content, m.direction, m.sent_at, m.sender_type, m.delivery_status, a.name AS agent_name, c.name AS customer_name, c.phone_number, json_agg( json_build_object( &apos;reader&apos;, u.name, &apos;read_at&apos;, rl.read_at ) ) FILTER (WHERE rl.id IS NOT NULL) AS read_by FROM messages m LEFT JOIN agents a ON m.sender_agent_id = a.id LEFT JOIN customers c ON m.sender_customer_id = c.id LEFT JOIN message_read_log rl ON rl.message_id = m.id LEFT JOIN users u ON rl.reader_user_id = u.id WHERE m.thread_id = $1 GROUP BY m.id, a.name, c.name, c.phone_number ORDER BY m.sent_at ASC LIMIT 50 OFFSET $2; Get all customers an agent interacted with (Messages tab): SELECT DISTINCT c.id, c.name, c.phone_number, t.id AS thread_id, t.last_message_at FROM message_threads t JOIN customers c ON t.customer_id = c.id JOIN messages m ON m.thread_id = t.id WHERE m.sender_agent_id = $1 AND t.thread_type = &apos;customer&apos; ORDER BY t.last_message_at DESC; 
